#!/usr/bin/env bash
set -Eeuo pipefail

onErr() {
  local rc=$?
  echo "[ERROR] rc=${rc} line=${BASH_LINENO[0]} cmd=${BASH_COMMAND}" >&2
}
onExit() {
  local rc=$?
  echo "[EXIT] rc=${rc}" >&2
}
trap onErr ERR
trap onExit EXIT

requireCmd() {
  local cmd="$1"
  command -v "$cmd" >/dev/null 2>&1 || {
    echo "ERROR: missing command: $cmd" >&2
    exit 127
  }
}

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

