TARGET_RAW="${1:-all}"
DATASETS_RAW="${2:-${SIFT_DATASETS:-100k,1m}}"

TARGET=""

normalizeTarget() {
  local t="$1"
  case "$t" in
    all|baselines|lsmvec|milvushnsw|qdrantlocal|weaviate|pgvectorhnsw|elasticsearch|elasticcloudhnsw|pinecone) echo "$t" ;;
    milvus) echo "milvushnsw" ;;
    qdrant) echo "qdrantlocal" ;;
    pgvector) echo "pgvectorhnsw" ;;
    elastic|elasticsearch) echo "elasticsearch" ;;
    elasticcloud) echo "elasticcloudhnsw" ;;
    *)
      echo ""
      ;;
  esac
}

TARGET="$(normalizeTarget "$TARGET_RAW")"

wantSection() {
  local section="$1" # milvushnsw|qdrantlocal|weaviate|pgvectorhnsw|elasticsearch|elasticcloudhnsw|pinecone|lsmvec
  case "$TARGET" in
    all) return 0 ;;
    baselines)
      [[ "$section" != "lsmvec" ]]
      return $?
      ;;
    *)
      [[ "$section" == "$TARGET" ]]
      return $?
      ;;
  esac
}

# datasets parsing, supports: 100k,1m,10m,all
DATASETS_NORM="${DATASETS_RAW,,}"
DATASETS_NORM="${DATASETS_NORM//[[:space:]]/}"
DATASETS_NORM=",$DATASETS_NORM,"

WANT_100K=false
WANT_1M=false
WANT_10M=false

if [[ "$DATASETS_NORM" == *",all,"* ]]; then
  WANT_100K=true
  WANT_1M=true
  WANT_10M=true
else
  [[ "$DATASETS_NORM" == *",100k,"* ]] && WANT_100K=true
  [[ "$DATASETS_NORM" == *",1m,"* ]] && WANT_1M=true
  [[ "$DATASETS_NORM" == *",10m,"* ]] && WANT_10M=true
fi

if [[ "$WANT_100K" != "true" && "$WANT_1M" != "true" && "$WANT_10M" != "true" ]]; then
  echo "ERROR: no datasets selected. Use 100k,1m,10m or all" >&2
  exit 1
fi

DATASETS_TAG="${DATASETS_NORM#,}"
DATASETS_TAG="${DATASETS_TAG%,}"
DATASETS_TAG="${DATASETS_TAG//,/__}"

verifyDatasetDir() {
  local dir="$1"
  if [[ ! -d "$dir" ]]; then
    echo "ERROR: dataset dir not found: $dir" >&2
    exit 1
  fi

  if [[ ! -f "$dir/train.parquet" ]]; then
    shopt -s nullglob
    local shards=("$dir"/train-*-of-*.parquet)
    shopt -u nullglob
    if [[ ${#shards[@]} -eq 0 ]]; then
      echo "ERROR: missing train.parquet or train-*-of-*.parquet in $dir" >&2
      exit 1
    fi
  fi

  [[ -f "$dir/test.parquet" ]] || { echo "ERROR: missing test.parquet in $dir" >&2; exit 1; }
  [[ -f "$dir/neighbors.parquet" ]] || { echo "ERROR: missing neighbors.parquet in $dir" >&2; exit 1; }
}

trainFileCount() {
  local dir="$1"
  if [[ -f "$dir/train.parquet" ]]; then
    echo 1
    return
  fi
  shopt -s nullglob
  local shards=("$dir"/train-*-of-*.parquet)
  shopt -u nullglob
  echo "${#shards[@]}"
}

getServerMemSummaryMiB() {
  awk '
    $1=="MemTotal:" {t=$2}
    $1=="MemAvailable:" {a=$2}
    END {
      if (t=="" || a=="") {
        printf "0.00\t0.00\t0.00\n"
        exit
      }
      used_kib = t - a
      printf "%.2f\t%.2f\t%.2f\n", used_kib/1024.0, t/1024.0, a/1024.0
    }
  ' /proc/meminfo 2>/dev/null || echo -e "0.00\t0.00\t0.00"
}

printSystemMemBefore() {
  local label="$1"
  local used total avail
  IFS=$'\t' read -r used total avail < <(getServerMemSummaryMiB)
  echo "system memory before running ${label} is ${used} MiB (used), total ${total} MiB, available ${avail} MiB"
}

ensureElasticsearchReachable() {
  local configuredScheme="${ELASTICSEARCH_SCHEME}"
  local configuredHost="${ELASTICSEARCH_HOST}"
  local configuredPort="${ELASTICSEARCH_PORT}"
  local retries="${ELASTICSEARCH_READY_RETRIES:-30}"

  local hosts=()
  local ports=()
  local schemes=()
  local host="" port="" scheme=""
  local attempted=""
  local dockerHintShown="false"

  appendUnique() {
    local value="$1"
    shift
    local -n arr="$1"
    local existing=""

    [[ -n "$value" ]] || return 0
    for existing in "${arr[@]}"; do
      [[ "$existing" == "$value" ]] && return 0
    done
    arr+=("$value")
  }

  tryUrl() {
    local url="$1"
    # Try with explicit auth first (for secured nodes), then without auth.
    curl -s -o /dev/null -m 3 -u "${ELASTICSEARCH_USER}:${ELASTICSEARCH_PASSWORD}" "$url" 2>/dev/null       || curl -s -o /dev/null -m 3 "$url" 2>/dev/null
  }

  appendUnique "$configuredHost" hosts
  appendUnique "$configuredPort" ports
  appendUnique "$configuredScheme" schemes

  if [[ "$configuredHost" == "localhost" ]]; then
    appendUnique "127.0.0.1" hosts
    appendUnique "host.docker.internal" hosts

    if command -v ip >/dev/null 2>&1; then
      appendUnique "$(ip route 2>/dev/null | awk '/^default/ {print $3; exit}')" hosts
    fi

    appendUnique "172.17.0.1" hosts
  fi

  # If an elasticsearch container exists, include its published host port for 9200/tcp.
  if command -v docker >/dev/null 2>&1     && docker ps -a --format '{{.Names}}' | grep -Fxq 'elasticsearch'; then
    local mappedPort=""
    mappedPort="$(docker port elasticsearch 9200/tcp 2>/dev/null | awk -F: 'NR==1 {print $NF}')"
    appendUnique "$mappedPort" ports
  fi

  if [[ "$configuredScheme" == "http" ]]; then
    appendUnique "https" schemes
  elif [[ "$configuredScheme" == "https" ]]; then
    appendUnique "http" schemes
  fi

  for scheme in "${schemes[@]}"; do
    for host in "${hosts[@]}"; do
      for port in "${ports[@]}"; do
        local url="${scheme}://${host}:${port}/"
        attempted+=" ${url}"

        for _ in $(seq 1 "$retries"); do
          if tryUrl "$url"; then
            if [[ "$host" != "$configuredHost" ]]; then
              echo "[INFO] Elasticsearch is reachable via ${host}; overriding ELASTICSEARCH_HOST for this run."
              ELASTICSEARCH_HOST="$host"
            fi
            if [[ "$port" != "$configuredPort" ]]; then
              echo "[INFO] Elasticsearch is reachable via port ${port}; overriding ELASTICSEARCH_PORT for this run."
              ELASTICSEARCH_PORT="$port"
            fi
            if [[ "$scheme" != "$configuredScheme" ]]; then
              echo "[INFO] Elasticsearch is reachable via scheme ${scheme}; overriding ELASTICSEARCH_SCHEME for this run."
              ELASTICSEARCH_SCHEME="$scheme"
            fi
            return 0
          fi
          sleep 1
        done
      done
    done
  done

  echo "ERROR: Elasticsearch is unreachable at ${configuredScheme}://${configuredHost}:${configuredPort}/ after ${retries}s per endpoint candidate" >&2
  echo "Hint: attempted endpoints:${attempted}" >&2
  echo "Hint: start baseline services first (e.g. ./start_baseline.sh elasticsearch)." >&2
  echo "Hint: if your node uses TLS, set ELASTICSEARCH_SCHEME=https." >&2
  if command -v docker >/dev/null 2>&1     && docker ps -a --format '{{.Names}}' | grep -Fxq 'elasticsearch'; then
    echo "Hint: an 'elasticsearch' container exists; check readiness with: docker logs --tail 100 elasticsearch" >&2
    echo "Hint: inspect mapped ports with: docker port elasticsearch 9200/tcp" >&2
    dockerHintShown="true"
  fi
  if [[ "$configuredHost" == "localhost" && "$dockerHintShown" != "true" ]]; then
    echo "Hint: in containers/devcontainers, set ELASTICSEARCH_HOST and ELASTICSEARCH_PORT to the Docker host endpoint." >&2
  fi
  exit 1
}

